import React, { useEffect, useState } from 'react';

const PaymentSuccess = () => {
  const [showCheck, setShowCheck] = useState(false);

  useEffect(() => {
    // Small delay to trigger the animation naturally
    const timer = setTimeout(() => setShowCheck(true), 100);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-white dark:bg-gray-800 rounded-lg">
      <div 
        className={`relative w-24 h-24 mb-6 transition-all duration-500 transform ${
          showCheck ? 'scale-100 opacity-100' : 'scale-50 opacity-0'
        }`}
      >
        <div className="absolute inset-0 bg-green-500 rounded-full shadow-lg flex items-center justify-center">
          <svg 
            className={`w-12 h-12 text-white transition-opacity duration-300 delay-300 ${
              showCheck ? 'opacity-100' : 'opacity-0'
            }`} 
            fill="none" 
            viewBox="0 0 24 24" 
            stroke="currentColor"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
          </svg>
        </div>
      </div>

      <h3 
        className={`text-2xl font-bold text-gray-900 dark:text-white transition-all duration-500 delay-200 ${
          showCheck ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0'
        }`}
      >
        Payment Verified!
      </h3>
      <p 
        className={`mt-2 text-gray-600 dark:text-gray-400 text-center transition-all duration-500 delay-300 ${
          showCheck ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0'
        }`}
      >
        Your booking has been secured successfully.
      </p>
    </div>
  );
};

export default PaymentSuccess;
